PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE weather (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            device_id TEXT,
            temperature_c REAL,
            humidity_percent REAL,
            heat_index_c REAL,
            co_raw INTEGER,
            co_voltage REAL,
            co_level TEXT,
            latitude REAL,
            longitude REAL,
            altitude_m REAL,
            speed_kmph REAL,
            course_deg REAL,
            satellites INTEGER,
            hdop REAL,
            utc_date TEXT,
            utc_time TEXT,
            dht_ok INTEGER,
            gps_valid INTEGER,
            arduino_uptime_ms INTEGER,
            gateway TEXT,
            timestamp REAL,
            received_at TEXT
        );
DELETE FROM sqlite_sequence;
COMMIT;
